        byteBuf.readBytes(buffer, 0, length);
        return new String(buffer);
    }

    private static int decodeDataLength(final ByteBuf byteBuf) {
        int result = 0;
        int i = 0;
        while (true) {
            int data = byteBuf.readUnsignedByte();
            result |= (data & 0x7f) << (7 * i);
            if (0 == (data & 0x80)) {
